window.GROWTH_DATA = {"generated": "2026-06-02T18:50:11.256387Z", "opportunities": {"updated": "2026-05-23T12:00:00.000000Z", "count": 21, "opportunities": [{"id": "opp-referrals-appointments-2026", "title": "Referrals & Appointments national funding", "source": "NHS England", "source_url": "https://htn.co.uk/2026/05/15/up-to-20-million-national-funding-for-referrals-and-appointments-opens/", "buyer": "NHS England", "type": "Funding offer", "category": "Patient-facing", "value": "£15m to £20m", "published": "2026-05-23T12:00:00Z", "deadline": "2026-05-31", "status": "Open", "summary": "National funding for NHS providers to scale the Booking and Referral Standard (BaRS), the e-Referral Service (e-RS), and the NHS App Wayfinder in 2026/27. Covers PIFU rollout, notifications, GIRFT pathway redesign, and Innovation Lead roles spanning divisions or whole systems.", "means": "Not a tender. A trust-facing pot from NHS England to fund adoption of existing national platforms (BaRS, e-RS, NHS App). Deadline is 8 days away. The trusts that win these are the ones who already have a supplier lined up and a delivery plan signed by a clinical SRO. If you supply into any of these stacks, your trust customers should already know whether they're bidding. Call them this week. If you don't have those relationships, the window is too short for new ones.", "tags": ["Funding offer", "Patient-facing", "Closes soon"]}, {"id": "opp-digital-medicines-mgmt-2026", "title": "Digital Medicines Management national funding", "source": "NHS England", "source_url": "https://htn.co.uk/2026/05/22/national-funding-opportunity-to-open-for-digital-medicines-management/", "buyer": "NHS England", "type": "Funding offer", "category": "Clinical systems & EPR", "value": "Not disclosed", "published": "2026-05-23T12:00:00Z", "deadline": "2026-07-17", "status": "Opens early June", "summary": "National revenue pot for NHS trusts to extend EPR and ePMA capability across two themes: medicines on admission (consuming structured GP medicines via GP Connect) and closed-loop medicines management (end-to-end interoperability across EPR, ePMA, automated dispensing cabinets and pharmacy stock control).", "means": "Follow-on to the digital medicines first-of-type schemes. Trust-facing on paper, supplier-dependent in practice. Applications expect evidence of supplier commitment, the commercial approach, and partnership with other trusts on the same stack. That last point is the tell: NHS England wants supplier-anchored consortia, not lone trusts. EPMA, GP Connect specialists, and dispensing-automation vendors should be the ones starting these conversations, not the trusts. Applications open early June and close 17 July at 5pm. If you supply EPMA or closed-loop stack, get three or more trust customers aligned in the next two weeks.", "tags": ["Funding offer", "EPMA", "GP Connect"]}, {"id": "std-sbs-ai-solutions", "title": "Healthcare AI Solutions Framework", "source": "NHS Shared Business Services", "source_url": "https://www.find-tender.service.gov.uk/Notice/001651-2025", "buyer": "NHS Shared Business Services", "type": "Framework", "category": "AI & analytics", "value": "£900,000,000", "published": "2026-05-23T12:00:00Z", "deadline": "2026-06-23", "status": "Open", "summary": "National framework for healthcare AI across eight lots: radiology and imaging, pathology and early detection, virtual and robotic health, predictive analytics, research and development, operational efficiency, advisory and specialised support, and combined solutions.", "means": "Updated 23 May: value lifted to £900m incl VAT, up from the original £150m estimate and the £750m figure carried earlier. A six-fold jump after supplier engagement that signals NHS SBS is expecting heavy lot-level competition. The procurement route for UK healthcare AI for the next four years. Lots 6 and 7 (operational efficiency, advisory) remain the quieter opportunity. Enquiry deadline 29 May, tender deadline 23 June. Tight: clinical evidence packs and DCB0129 documentation take weeks.", "tags": ["Framework", "AI", "Updated", "Closes soon"]}, {"id": "std-gp-it-futures", "title": "Tech Innovation Framework / GP IT Futures", "source": "NHS England Digital", "source_url": "https://digital.nhs.uk/services/digital-care-services-catalogue/tech-innovation-framework", "buyer": "NHS England", "type": "Framework", "category": "Clinical systems & EPR", "value": "", "published": "2026-05-19", "deadline": "", "status": "Rolling", "summary": "Assured core GP IT systems and digital products for primary care, bought via the Digital Care Services catalogue. Tech Innovation Framework is the successor to GP IT Futures.", "means": "Essential route for anything touching primary care. GP IT Futures continuity contracts run only to June 2026. If primary care is a target market, getting onto TIF is the gating step.", "tags": ["Framework", "Primary care"]}, {"id": "std-medtech-funding-mandate", "title": "MedTech Funding Mandate", "source": "NHS England / Accelerated Access Collaborative", "source_url": "https://www.england.nhs.uk/aac/what-we-do/how-can-the-aac-help-me/the-medtech-funding-mandate/", "buyer": "NHS England", "type": "Adoption route", "category": "Other digital health", "value": "", "published": "2026-04-01", "deadline": "", "status": "Ongoing", "summary": "Mandates NHS commissioners and providers to fund a defined list of NICE-approved cost-saving devices, diagnostics and digital products.", "means": "Not a tender. It's a route to guaranteed local funding. Eligibility: positive NICE guidance, net saving within three years, budget impact under £20m a year. Worth understanding early if a NICE pathway is in reach.", "tags": ["Adoption route", "NICE"]}, {"id": "std-gcloud", "title": "G-Cloud (Digital Marketplace)", "source": "Crown Commercial Service", "source_url": "https://www.digitalmarketplace.service.gov.uk/", "buyer": "Crown Commercial Service", "type": "Framework", "category": "Infrastructure & cloud", "value": "", "published": "2026-01-01", "deadline": "", "status": "Rolling", "summary": "Cross-government framework for cloud hosting, software (SaaS) and digital support. The primary procurement route for software-based digital health products.", "means": "The most relevant framework for digital health SaaS. Being listed makes a product discoverable to every NHS buyer. Application windows open periodically, worth tracking.", "tags": ["Framework", "Cloud"]}, {"id": "std-sbs-spark-dps", "title": "Spark DPS: Innovative Health & Care Solutions", "source": "NHS Shared Business Services", "source_url": "https://www.sbs.nhs.uk/services/framework-agreements/spark-dynamic-purchasing-system", "buyer": "NHS Shared Business Services", "type": "Dynamic Purchasing System", "category": "Other digital health", "value": "", "published": "2026-04-01", "deadline": "", "status": "Rolling", "summary": "DPS for innovative SME-developed health and care products and services. Lower barrier to entry than a full framework, suppliers can join at any point.", "means": "The SME-friendly route into NHS procurement. Lower paperwork burden than a framework, and you can join any time, not just at a renewal window. Best fit for devices and remote monitoring; weaker for pure SaaS (use G-Cloud instead).", "tags": ["DPS", "SME"]}, {"id": "std-ccs-vertical-app", "title": "Vertical Application Solutions (RM6259)", "source": "Crown Commercial Service", "source_url": "https://www.crowncommercial.gov.uk/agreements/RM6259", "buyer": "Crown Commercial Service", "type": "Framework", "category": "Clinical systems & EPR", "value": "", "published": "2026-01-01", "deadline": "", "status": "Rolling call-offs", "summary": "Cross-government framework for sector-specific software. Lot 1 covers Health, Welfare and Community products, including EPRs, patient management and population health platforms.", "means": "The right framework for full EPR or sector-specific platforms that don't fit G-Cloud's SaaS shape. Call-offs are bigger and slower-moving than G-Cloud, but commitments are longer.", "tags": ["Framework", "EPR"]}, {"id": "std-noe-cpc-digital", "title": "NOE CPC Digital & IT Frameworks", "source": "NOE CPC (NHS North of England Commercial Procurement Collaborative)", "source_url": "https://www.noecpc.nhs.uk/our-frameworks", "buyer": "NOE CPC", "type": "Framework hub", "category": "Infrastructure & cloud", "value": "", "published": "2026-04-01", "deadline": "", "status": "Multiple frameworks open", "summary": "Northern NHS procurement hub running a portfolio of digital and IT frameworks. Member trusts across the North of England buy directly from these.", "means": "If your target buyers are northern trusts, NOE CPC frameworks reach them faster than national routes. Part of NHS Procurement in Partnership, so being listed on one hub often surfaces you to all four.", "tags": ["Framework", "Regional"]}, {"id": "std-lpp-digital", "title": "NHS LPP Digital & Healthtech Frameworks", "source": "London Procurement Partnership (NHS LPP)", "source_url": "https://www.lpp.nhs.uk/our-frameworks/", "buyer": "NHS LPP", "type": "Framework hub", "category": "Infrastructure & cloud", "value": "", "published": "2026-04-01", "deadline": "", "status": "Multiple frameworks open", "summary": "London-led NHS procurement hub running digital, workforce and clinical frameworks. Member trusts across London and the South East access these directly.", "means": "London concentration of trusts means a single LPP framework reach can be significant. Good complement to NOE CPC for full-England coverage.", "tags": ["Framework", "Regional"]}, {"id": "std-pip-federation", "title": "NHS Procurement in Partnership (PiP)", "source": "NHS PiP (NOE CPC, NHS LPP, NHS Commercial Solutions, East of England NHS Collaborative)", "source_url": "https://www.nhspip.uk/", "buyer": "NHS PiP", "type": "Federation", "category": "Other digital health", "value": "", "published": "2026-04-01", "deadline": "", "status": "Active", "summary": "Federation of the four NHS regional procurement collaboratives. Member trusts can access the framework portfolios of all four hubs.", "means": "Worth knowing how this federation works. Being on one hub's framework can mean reach across all four hub regions, depending on call-off terms. Reduces the duplication of selling into multiple regional hubs.", "tags": ["Federation", "Regional"]}, {"id": "std-ccs-network-services", "title": "Network Services 3 (RM6116)", "source": "Crown Commercial Service", "source_url": "https://www.crowncommercial.gov.uk/agreements/RM6116", "buyer": "Crown Commercial Service", "type": "Framework", "category": "Infrastructure & cloud", "value": "", "published": "2026-01-01", "deadline": "", "status": "Rolling call-offs", "summary": "Cross-government framework for network, telecoms and connectivity services. Includes NHS-relevant call-offs for HSCN connectivity, secure messaging and unified comms.", "means": "Only relevant if your product needs HSCN-grade networking or telephony integration. Otherwise stick to G-Cloud. Useful for clinical comms platforms riding on top of NHS network stacks.", "tags": ["Framework", "Telecoms"]}, {"id": "std-sbs-clinical-comms", "title": "Clinical Communications Procurement Framework", "source": "NHS Shared Business Services", "source_url": "https://www.sbs.nhs.uk/services/framework-agreements/", "buyer": "NHS Shared Business Services", "type": "Framework", "category": "Clinical systems & EPR", "value": "", "published": "2026-04-01", "deadline": "", "status": "Rolling call-offs", "summary": "National framework for clinical communication tools including secure messaging, task management, and care coordination platforms. Successor route to legacy bleep replacement.", "means": "If you are in the secure messaging or clinical task management space, this is the procurement route. Trusts use this to replace bleeps and pagers, a large active market.", "tags": ["Framework", "Comms"]}, {"id": "std-nia-accelerator", "title": "NHS Innovation Accelerator (NIA)", "source": "NHS England / Health Innovation Network", "source_url": "https://nhsaccelerator.com/", "buyer": "NHS England", "type": "Adoption route", "category": "Other digital health", "value": "", "published": "2026-05-19", "deadline": "", "status": "Annual cohorts", "summary": "National accelerator for proven innovations seeking adoption across the NHS. Fellows get sponsorship, NHS connections, and a credibility marker, not direct procurement.", "means": "Not a tender. It is a credibility and access route for products with at least one NHS deployment. Cohort applications open annually. Worth applying if you have evidence and want NHS visibility at scale.", "tags": ["Adoption route", "Accelerator"]}, {"id": "std-digitalhealth-london", "title": "DigitalHealth.London Accelerator", "source": "DigitalHealth.London (NHS England, MedCity, partner ICSs)", "source_url": "https://digitalhealth.london/accelerator", "buyer": "DigitalHealth.London", "type": "Accelerator", "category": "Other digital health", "value": "", "published": "2026-04-01", "deadline": "", "status": "Annual cohorts", "summary": "12-month accelerator for SMEs with digital products solving NHS challenges in London. Includes NHS navigator support, evidence generation help, and direct trust introductions.", "means": "Most useful if your product is at the post-pilot stage and needs structured introductions to London ICS commissioners. Applications usually open in the spring.", "tags": ["Accelerator", "Regional"]}, {"id": "std-aac-itp", "title": "Innovation Technology Payment (ITP), legacy", "source": "NHS England / Accelerated Access Collaborative", "source_url": "https://www.england.nhs.uk/aac/what-we-do/", "buyer": "NHS England", "type": "Funding route", "category": "Other digital health", "value": "", "published": "2026-04-01", "deadline": "", "status": "Closed", "summary": "Legacy. The Innovation Technology Payment ran selected high-impact innovations on a national tariff. The programme has wound down. The MedTech Funding Mandate (MTFM) is its functional successor for cost-saving NICE-approved technologies.", "means": "Listed here for context only. If you were considering ITP as a route, the live equivalent is the MedTech Funding Mandate. See the MTFM entry.", "tags": ["Adoption route", "AAC"]}, {"id": "std-mhra-ai-airlock", "title": "AI Airlock (MHRA regulatory sandbox)", "source": "Medicines and Healthcare products Regulatory Agency", "source_url": "https://www.gov.uk/government/publications/ai-airlock-the-regulatory-sandbox-for-aiamd", "buyer": "MHRA", "type": "Regulatory sandbox", "category": "AI & analytics", "value": "", "published": "2026-04-01", "deadline": "", "status": "Periodic cohorts", "summary": "MHRA sandbox for AI as a Medical Device (AIaMD) developers. Lets you work through regulatory questions with MHRA before market authorisation.", "means": "Not procurement. It is regulatory derisking. If your product is an AIaMD heading for UKCA / CE marking, joining a cohort is the most efficient way to align with the regulator early. Cohort calls open periodically.", "tags": ["Regulatory", "AI"]}, {"id": "std-nhs-england-tech-frameworks", "title": "NHS England Digital Care Services Catalogue", "source": "NHS England Digital", "source_url": "https://digital.nhs.uk/services/digital-care-services-catalogue", "buyer": "NHS England", "type": "Catalogue", "category": "Clinical systems & EPR", "value": "", "published": "2026-04-01", "deadline": "", "status": "Rolling", "summary": "Catalogue of assured digital products for primary care, including GP IT systems, prescribing and patient management tools. Successor to the GP Systems of Choice framework.", "means": "If primary care is in scope, this is the assurance catalogue you need to be on. Gating step for adoption by GP practices. Application is non-trivial: cybersecurity, clinical safety, data interoperability requirements all need to pass.", "tags": ["Catalogue", "Primary care"]}, {"id": "std-gpsoc-legacy", "title": "GP Systems of Choice (GPSoC)", "source": "NHS Digital (legacy)", "source_url": "https://digital.nhs.uk/services/gp-systems-of-choice", "buyer": "NHS Digital", "type": "Legacy framework", "category": "Clinical systems & EPR", "value": "", "published": "2014-01-01", "deadline": "2018-12-31", "status": "Closed", "summary": "The framework that ran GP IT systems procurement from 2014 to 2018. Superseded by GP IT Futures, which is itself transitioning to the Tech Innovation Framework.", "means": "Closed, but instructive. Knowing the GPSoC, GP IT Futures, TIF lineage helps founders read where primary care procurement is heading next. The pattern: each generation widens supplier eligibility while raising the assurance bar.", "tags": ["Framework", "Closed", "Primary care"]}, {"id": "std-hssf-legacy", "title": "Health Systems Support Framework (HSSF)", "source": "NHS England", "source_url": "https://www.england.nhs.uk/health-systems-support-framework/", "buyer": "NHS England", "type": "Legacy framework", "category": "Other digital health", "value": "", "published": "2018-10-01", "deadline": "2025-12-31", "status": "Closed to new call-offs", "summary": "NHS England framework for population health management, digital and analytics. NHS England has stopped initiating new call-offs but existing ones continue. A successor framework has been signalled.", "means": "Worth tracking the successor announcement. HSSF supported a lot of population health platform work. Whatever replaces it will set the procurement route for the next generation of population health and PHM tools.", "tags": ["Framework", "Closed", "Population health"]}, {"id": "std-nhsx-ai-award-legacy", "title": "NHSX AI in Health and Care Award (legacy rounds)", "source": "NHSX / NIHR / Accelerated Access Collaborative", "source_url": "https://www.nihr.ac.uk/research-funding/funding-programmes/artificial-intelligence-in-health-and-care-award", "buyer": "NHSX / NIHR", "type": "Award programme", "category": "AI & analytics", "value": "£140m total across rounds", "published": "2020-09-01", "deadline": "2023-04-30", "status": "Closed", "summary": "Four-round AI award programme that funded NHS deployments of AI technologies across imaging, decision support and operational use cases. Rounds 1-4 ran 2020-2023; programme now wound into the NIHR pathway.", "means": "Closed, but the awarded companies are a who's-who of UK AI healthtech. The award structure (development through to real-world evaluation) became the template for NHS-aligned AI funding. Worth knowing the alumni for partnership and patterns.", "tags": ["Award", "Closed", "AI"]}]}, "opportunitiesLive": {"updated": "2026-06-02T18:50:11.204642Z", "count": 2, "opportunities": [{"id": "fts-050965-2026", "title": "The Provision of Enhanced Virtual Care Project", "source": "Find a Tender", "source_url": "https://www.find-tender.service.gov.uk/Notice/ocds-h6vhtk-06a933", "buyer": "Royal Free London NHS Foundation Trust", "type": "Tender", "category": "Remote monitoring", "value": "GBP 12,000,000", "published": "2026-05-29T15:53:40+01:00", "deadline": "2026-06-29T10:00:00+01:00", "summary": "Royal Free London NHS Foundation Trust is conducting a procurement for an Enhanced Virtual Care programme using the Competitive Process under the Health Care Services (Provider Selection Regime) Regulations 2023. The Service provides digitally enabled proactive care for people wi…", "cpv": ["85323000"], "tags": ["Tender"], "means": ""}, {"id": "fts-049462-2026", "title": "Fertility EPR System", "source": "Find a Tender", "source_url": "https://www.find-tender.service.gov.uk/Notice/ocds-h6vhtk-06a595", "buyer": "Barts Health NHS Trust", "type": "Tender", "category": "Clinical systems & EPR", "value": "GBP 350,000", "published": "2026-05-27T10:45:10+01:00", "deadline": "2026-06-15T12:00:00+01:00", "summary": "For the Provision of a Fertility EPR System", "cpv": [], "tags": ["Tender", "Closes soon"], "means": ""}]}, "grants": {"updated": "2026-05-23T12:00:00.000000Z", "count": 22, "grants": [{"id": "grant-wellcome-mental-health-prize-2026", "title": "Wellcome Prize for Mental Health Science (with Nature)", "source": "Wellcome Trust", "source_url": "https://wellcome.org/insights/articles/wellcome-announces-global-prize-accelerate-new-mental-health-interventions", "type": "International prize", "category": "Condition-specific", "value": "$1m winner, three finalists at $250k each", "published": "2026-05-23T12:00:00Z", "deadline": "2026-09-18", "status": "Open", "summary": "Global prize from Wellcome in partnership with Springer Nature for research that improves outcomes for anxiety, depression, and psychosis. Open to teams worldwide. Shortlisting April 2027, winner announced June 2027.", "means": "Prize, not a grant. Recognition plus cash for work that's already advanced enough to show measured outcomes. Wellcome and Nature together is an unusually clean credibility signal for a UK digital therapeutic in mental health, particularly anything with peer-reviewed evidence. The Nature association means judging will lean academic. Pure product entries without a research backbone won't shortlist. Worth a submission if you have a published outcomes paper or active RCT data in anxiety, depression, or psychosis. Skip if pre-evidence.", "tags": ["Prize", "International", "Mental health"]}, {"id": "grant-sbri-healthcare", "title": "SBRI Healthcare: themed competitions", "source": "SBRI Healthcare", "source_url": "https://sbrihealthcare.co.uk/competitions", "type": "Grant programme", "category": "NHS-aligned innovation", "value": "Phase 1 £50k-£150k · Phase 2 up to £1m", "published": "2026-05-19", "deadline": "", "status": "Competitions in waves", "summary": "Themed competitions for innovations addressing unmet NHS need. Open to digital, AI and device innovations. Includes an Investment Readiness programme.", "means": "The flagship NHS-aligned non-dilutive funder. As much a credibility marker as a cash injection. An SBRI award signals NHS validation to later investors.", "tags": ["Grant", "Non-dilutive"]}, {"id": "grant-nihr-i4i", "title": "NIHR Invention for Innovation (i4i): Product Development Awards", "source": "National Institute for Health and Care Research", "source_url": "https://www.nihr.ac.uk/research-funding/funding-programmes/invention-for-innovation", "type": "Grant programme", "category": "Translational funding", "value": "SMEs eligible for up to 100% funding", "published": "2026-05-23T12:00:00Z", "deadline": "", "status": "Next round opens 27 May", "summary": "Translational funding for medical devices, IVDs and digital health technologies bridging proof-of-concept to real-world clinical adoption. Two-stage application: outline first, full bid on invitation.", "means": "Best fit for a product with early clinical evidence that needs the push to adoption-readiness. The two-stage process lets you test an outline cheaply before committing to a full bid. Next call opens 27 May, which is four working days to finalise the outline draft. If you are not already in conversation with an NHS clinical co-applicant, that is the blocker to fix this week, not the outline itself.", "tags": ["Grant", "Non-dilutive"]}, {"id": "grant-nihr-eme", "title": "NIHR Efficacy and Mechanism Evaluation (EME) Programme", "source": "National Institute for Health and Care Research", "source_url": "https://www.nihr.ac.uk/research-funding/funding-programmes/efficacy-and-mechanism-evaluation", "type": "Grant programme", "category": "Clinical evidence", "value": "Varies", "published": "2026-05-01", "deadline": "2026-08-05", "status": "Open, outline stage", "summary": "Funds evaluation of efficacy and the mechanisms behind health interventions, including digital and technology-enabled interventions.", "means": "Relevant where the gap is hard clinical evidence rather than product build. Outline applications close 5 August 2026.", "tags": ["Grant", "Closes soon"]}, {"id": "grant-biomedical-catalyst", "title": "Innovate UK: Biomedical Catalyst", "source": "Innovate UK (UKRI)", "source_url": "https://www.ukri.org/councils/innovate-uk/", "type": "Grant programme", "category": "R&D funding", "value": "Up to ~£2m for large projects", "published": "2026-05-01", "deadline": "", "status": "Rolling competitions", "summary": "Supports SMEs developing innovative solutions to health and healthcare challenges, from small projects through to large collaborative R&D.", "means": "The broadest UK non-dilutive R&D funder for healthtech. Pairs well with SBRI/NIHR (different stages of the same journey).", "tags": ["Grant", "R&D"]}, {"id": "grant-eic-accelerator", "title": "EIC Accelerator", "source": "Horizon Europe / European Innovation Council", "source_url": "https://eic.ec.europa.eu/eic-funding-opportunities/eic-accelerator_en", "type": "International grant", "category": "Deep-tech funding", "value": "Up to ~€2.5m grant + equity", "published": "2026-05-01", "deadline": "2026-07-08", "status": "Open, next cut-off", "summary": "Grant plus equity for deep-tech SMEs and startups. UK organisations are eligible following association to Horizon Europe.", "means": "Six fixed cut-offs a year, predictable enough to plan a submission around. Next cut-off 8 July 2026; further cut-offs 2 September and 4 November.", "tags": ["Grant", "International", "Closes soon"]}, {"id": "grant-horizon-health", "title": "Horizon Europe: Health Cluster (Cluster 1)", "source": "European Commission", "source_url": "https://research-and-innovation.ec.europa.eu/funding/funding-opportunities/funding-programmes-and-open-calls/horizon-europe/cluster-1-health_en", "type": "International grant", "category": "Collaborative R&I", "value": "Up to ~€90m per call", "published": "2026-05-01", "deadline": "", "status": "2026-27 work programme open", "summary": "Collaborative health research and innovation funding. UK organisations can apply as part of a consortium of at least three countries, one an EU member state.", "means": "Big money, but consortium-bound. Best approached as a partner in a larger bid rather than a solo route. The 2026-27 work programme is published; specific calls have fixed deadlines.", "tags": ["Grant", "International"]}, {"id": "grant-nihr-i4i-connect", "title": "NIHR i4i Connect", "source": "National Institute for Health and Care Research", "source_url": "https://www.nihr.ac.uk/research-funding/funding-programmes/invention-for-innovation/i4i-connect", "type": "Grant programme", "category": "Translational funding", "value": "Up to £150k", "published": "2026-05-01", "deadline": "", "status": "Periodic calls", "summary": "Smaller, more accessible sibling to NIHR i4i Product Development Awards. Bridges earlier-stage device and digital health work towards adoption readiness.", "means": "Best fit for SMEs with promising tech but pre-clinical-evidence. Cheaper to apply for than full Product Development Awards. Use it as a stepping stone to the full i4i scheme.", "tags": ["Grant", "Non-dilutive"]}, {"id": "grant-nihr-pgfar", "title": "NIHR Programme Grants for Applied Research", "source": "National Institute for Health and Care Research", "source_url": "https://www.nihr.ac.uk/research-funding/funding-programmes/programme-grants-for-applied-research", "type": "Grant programme", "category": "Applied research", "value": "Typically £1.5m-£3m over 3-5 years", "published": "2026-05-01", "deadline": "", "status": "Periodic calls", "summary": "Large multi-year applied research grants for programmes addressing NHS priorities. Two-stage application: outline then full bid.", "means": "Big money for university partnerships. Healthtech SMEs typically join as industry partners on academic-led bids rather than leading their own. Worth knowing which research groups are bidding in your therapeutic area.", "tags": ["Grant", "Non-dilutive"]}, {"id": "grant-nihr-hta", "title": "NIHR Health Technology Assessment (HTA) Programme", "source": "National Institute for Health and Care Research", "source_url": "https://www.nihr.ac.uk/research-funding/funding-programmes/health-technology-assessment", "type": "Grant programme", "category": "Clinical evidence", "value": "Varies, often £500k-£2m+", "published": "2026-05-23T12:00:00Z", "deadline": "2026-09-02", "status": "Open commissioned call", "summary": "Funds research producing the evidence base for the NHS: clinical effectiveness, cost-effectiveness, and broader impact of health technologies including digital tools.", "means": "A commissioned call is open now (closes 2 September) for applications addressing James Lind Alliance priority areas, NICE-flagged research gaps, and themes not well covered in the existing HTA portfolio. The route to fund a definitive clinical trial of your digital health technology. Long timelines (years), academic-led, but produces NICE-grade evidence that unlocks reimbursement. If your near-term need is product evidence, look at i4i Connect or Innovate UK first; HTA is the multi-year play.", "tags": ["Grant", "Non-dilutive"]}, {"id": "grant-innovate-uk-smart", "title": "Innovate UK Smart Grants", "source": "Innovate UK (UKRI)", "source_url": "https://www.ukri.org/opportunity/innovate-uk-smart-grants/", "type": "Grant programme", "category": "R&D funding", "value": "£100k-£2m, single or collaborative", "published": "2026-05-01", "deadline": "", "status": "Multiple rounds per year", "summary": "Open-themed grants for game-changing innovations from UK SMEs in any sector. Health and digital health applications are eligible and well-represented.", "means": "The most flexible Innovate UK route. Open theme means you set the scope. Health-focused bids do well if they show clear NHS demand and commercial viability. Multiple rounds a year, predictable cycle.", "tags": ["Grant", "R&D"]}, {"id": "grant-wellcome-innovator", "title": "Wellcome Innovator Awards", "source": "Wellcome Trust", "source_url": "https://wellcome.org/grant-funding/schemes/innovator-awards", "type": "Grant programme", "category": "Translational funding", "value": "Up to £750k (Lead) / up to £2m (Translational)", "published": "2026-05-01", "deadline": "", "status": "Continuous, with deadlines", "summary": "Funds early-to-mid-stage translation of basic research into health innovations. Open to both academics and SMEs in partnership.", "means": "Strong fit if your tech is grounded in scientific discovery, not just engineering. Wellcome values the underlying research story as much as the product. Good for therapeutic AI, novel diagnostics, biosignal work.", "tags": ["Grant", "Non-dilutive"]}, {"id": "grant-mrc-cic", "title": "MRC Confidence in Concept", "source": "Medical Research Council (UKRI)", "source_url": "https://www.ukri.org/councils/mrc/guidance-for-applicants/types-of-funding/translational-research/confidence-in-concept/", "type": "Grant programme", "category": "Translational funding", "value": "Typically £50k-£200k per project", "published": "2026-05-01", "deadline": "", "status": "Block grants distributed by institutions", "summary": "Block-funded scheme distributed via universities and research institutes to support early-stage translation. Funds go to internal CiC competitions at each host.", "means": "Indirect route. You apply via your university or research partner, not directly to MRC. Useful for de-risking a digital health concept before chasing larger NIHR or Innovate UK funding.", "tags": ["Grant", "Non-dilutive"]}, {"id": "grant-lifearc-innovation", "title": "LifeArc Translational Awards", "source": "LifeArc", "source_url": "https://www.lifearc.org/our-impact/our-funding/", "type": "Grant programme", "category": "Translational funding", "value": "Project-dependent, often £100k-£500k", "published": "2026-05-01", "deadline": "", "status": "Open calls", "summary": "Medical research charity that funds translation of academic research into patient impact. Active in diagnostics, rare disease, and digital therapeutics.", "means": "Charity money with industry-style rigour. Best fit for diagnostic and therapeutic devices with a clear unmet-need narrative. Less common for general-purpose health software.", "tags": ["Grant", "Charity"]}, {"id": "grant-health-foundation-q", "title": "Health Foundation: Q Exchange", "source": "The Health Foundation", "source_url": "https://q.health.org.uk/q-exchange/", "type": "Grant programme", "category": "Quality improvement", "value": "£10k-£40k typical", "published": "2026-05-01", "deadline": "", "status": "Annual themed rounds", "summary": "Small grants for NHS quality improvement projects from members of the Q community. Funds collaborative ideas chosen by community vote.", "means": "Small money but useful pilot funding if you have an NHS partner inside Q. Builds frontline relationships and produces case studies. Not a route to scale, but a route to credibility.", "tags": ["Grant", "Pilot"]}, {"id": "grant-bhf-translational", "title": "British Heart Foundation Translational Awards", "source": "British Heart Foundation", "source_url": "https://www.bhf.org.uk/for-professionals/information-for-researchers/what-we-fund", "type": "Grant programme", "category": "Condition-specific", "value": "Varies, typically £100k-£500k", "published": "2026-05-01", "deadline": "", "status": "Periodic calls", "summary": "Cardiovascular disease-specific funding for translational research and innovation, including device and digital health work with a cardiac focus.", "means": "Only relevant if your product has a clear cardiology angle. BHF money is competitive but the disease focus narrows the field dramatically. Pairs well with NHS cardiac network engagement.", "tags": ["Grant", "Condition-specific"]}, {"id": "grant-cruk-innovation", "title": "Cancer Research UK Innovation Awards", "source": "Cancer Research UK", "source_url": "https://www.cancerresearchuk.org/funding-for-researchers/our-funding-schemes", "type": "Grant programme", "category": "Condition-specific", "value": "Varies by scheme", "published": "2026-05-01", "deadline": "", "status": "Multiple schemes open", "summary": "Portfolio of grants for cancer research and innovation, including early detection, diagnostics, treatment and digital tools.", "means": "Cancer-specific. Strong fit for AI-in-imaging, early detection biomarkers, and digital decision support in oncology. Look for the Convergence Sciences and Early Detection schemes specifically.", "tags": ["Grant", "Condition-specific"]}, {"id": "grant-hdr-uk", "title": "Health Data Research UK funding calls", "source": "HDR UK", "source_url": "https://www.hdruk.ac.uk/funding-opportunities/", "type": "Grant programme", "category": "Data infrastructure", "value": "Programme-dependent", "published": "2026-05-01", "deadline": "", "status": "Multiple programmes", "summary": "UK-wide programme funding work on health data infrastructure, federated analytics, and trusted research environments. Periodic open calls.", "means": "Niche but valuable if your work touches health data infrastructure, Trusted Research Environments, or federated analytics. Often co-funded with NIHR or industry partners.", "tags": ["Grant", "Data"]}, {"id": "grant-dhsc-policy-pots", "title": "DHSC Policy Innovation Funds (various)", "source": "Department of Health and Social Care", "source_url": "https://www.gov.uk/government/organisations/department-of-health-and-social-care", "type": "Policy-linked funding", "category": "Strategic", "value": "Varies, often large and time-limited", "published": "2026-05-01", "deadline": "", "status": "Episodic", "summary": "Periodic policy-driven funding pots from DHSC tied to current strategy (AI diagnostic funds, 10 Year Plan allocations, workforce productivity funds). Hard to track centrally.", "means": "The most opaque category. Pots appear, often announced via ministerial speeches or NHS England circulars, with short deadlines. Following DHSC press releases and NHS England announcements is the only way to spot them in time. High editorial value here.", "tags": ["Grant", "Policy"]}, {"id": "grant-sbri-ai-2022-legacy", "title": "SBRI Healthcare: AI in Health and Care themed call (2022)", "source": "SBRI Healthcare", "source_url": "https://sbrihealthcare.co.uk/competitions", "type": "Themed grant call", "category": "NHS-aligned innovation", "value": "Phase 1 up to £100k; Phase 2 up to £1m", "published": "2022-04-01", "deadline": "2022-07-31", "status": "Closed", "summary": "SBRI Healthcare's themed competition focused on AI in health and care. Funded Phase 1 feasibility and Phase 2 development awards.", "means": "Closed call, but a useful reference point. SBRI typically rotates themes year on year; an AI-focused round is likely again. The 2022 alumni list shows where SBRI saw maturity in AI for NHS use cases.", "tags": ["Grant", "Closed", "AI"]}, {"id": "grant-innovate-uk-bc-2024", "title": "Innovate UK Biomedical Catalyst (2024 round)", "source": "Innovate UK (UKRI)", "source_url": "https://www.ukri.org/councils/innovate-uk/", "type": "Grant programme round", "category": "R&D funding", "value": "Up to £4m per project", "published": "2024-02-01", "deadline": "2024-05-08", "status": "Closed", "summary": "The 2024 round of Innovate UK's Biomedical Catalyst, funding industry-led collaborative R&D in health innovation. Annual cadence.", "means": "Closed for 2024, but the cycle is reliable. Use the 2024 awardee list to spot which subsectors Innovate UK is currently betting on, and plan a 2026 submission against that pattern.", "tags": ["Grant", "Closed", "R&D"]}, {"id": "grant-nhsx-ai-award-r3", "title": "NHSX AI Award (Round 3)", "source": "NHSX / NIHR / Accelerated Access Collaborative", "source_url": "https://www.nihr.ac.uk/research-funding/funding-programmes/artificial-intelligence-in-health-and-care-award", "type": "Award programme", "category": "NHS-aligned innovation", "value": "Up to £20m total", "published": "2022-01-01", "deadline": "2022-04-30", "status": "Closed", "summary": "Round 3 of the NHSX AI in Health and Care Award. Funded translation through to real-world clinical evaluation for AI products with credible evidence.", "means": "Closed. Programme is now wound into the broader NIHR pathway. The Round 3 awardee list is the most relevant snapshot of what survived NHSX's rigour.", "tags": ["Grant", "Closed", "AI"]}]}, "directory": {"updated": "2026-05-15T11:46:13.975430Z", "procurement_count": 26, "grant_count": 19, "procurement": [{"Source": "Find a Tender Service (FTS)", "Type": "Statutory portal", "Owner / operator": "UK Government (Cabinet Office)", "Geographic scope": "UK-wide", "What it covers": "Higher-value public contract notices, tenders, awards and pipeline/planned-procurement notices (post Procurement Act 2023).", "URL": "https://www.find-tender.service.gov.uk", "Feed / API": "Yes - API", "Update cadence": "Continuous / real-time", "Login to view?": "No", "Notes & relevance to digital health": "TIER 1 backbone. OCDS JSON API (release & record packages), v1.1.5. Dev docs at /Developer/Documentation. Fully automatable."}, {"Source": "Contracts Finder", "Type": "Statutory portal", "Owner / operator": "UK Government (Cabinet Office)", "Geographic scope": "England-focused", "What it covers": "Lower-value contracts (£12k+ central gov), pipeline/planned procurement, some award notices.", "URL": "https://www.contractsfinder.service.gov.uk", "Feed / API": "Yes - API", "Update cadence": "Continuous", "Login to view?": "No (free account for saved searches)", "Notes & relevance to digital health": "TIER 1 backbone. OCDS API + CSV export. Dev docs at /apidocumentation. Fully automatable."}, {"Source": "Atamis - Health Family eCommercial System", "Type": "NHS portal", "Owner / operator": "Atamis (for NHS / DHSC)", "Geographic scope": "England (most NHS trusts + NHS England)", "What it covers": "NHS tender notices, planned procurements and framework opportunities across the majority of NHS organisations.", "URL": "https://atamis-1928.my.site.com/s/Welcome", "Feed / API": "Alerts only", "Update cadence": "Continuous", "Login to view?": "Free supplier registration for alerts", "Notes & relevance to digital health": "TIER 3, closest thing to a single NHS portal (44k+ suppliers). No open API; free email business alerts. Monitor, do not scrape."}, {"Source": "NHS Shared Business Services (SBS)", "Type": "Framework operator", "Owner / operator": "NHS SBS (DHSC / Sopra Steria JV)", "Geographic scope": "England + UK-wide national frameworks", "What it covers": "National framework agreements, incl. the £900m (inc VAT) Healthcare AI Solutions framework SBS10523 (8 lots, submissions close 23 Jun 2026, runs via SAP Ariba).", "URL": "https://www.sbs.nhs.uk/services/procurement", "Feed / API": "No", "Update cadence": "Periodic (framework launches)", "Login to view?": "No to browse", "Notes & relevance to digital health": "TIER 3, the 'stealth release' problem source. ~40% of the NHS uses SBS. Watch frameworks page + cross-check FTS. High editorial value."}, {"Source": "NHS Supply Chain / Spark DPS", "Type": "Framework operator / DPS", "Owner / operator": "Supply Chain Coordination Ltd", "Geographic scope": "England", "What it covers": "Products & consumables; Spark DPS = innovative med-tech and remote monitoring, open-entry for SMEs.", "URL": "https://www.supplychain.nhs.uk", "Feed / API": "Alerts only", "Update cadence": "Spark DPS open continuously (join anytime)", "Login to view?": "Free registration", "Notes & relevance to digital health": "Spark DPS is the SME-friendly innovation route, strongest for devices/remote monitoring, less so for pure software."}, {"Source": "Crown Commercial Service (CCS) - Health", "Type": "Framework operator", "Owner / operator": "Crown Commercial Service (Cabinet Office)", "Geographic scope": "UK-wide cross-government incl. NHS", "What it covers": "Cross-government frameworks, several health-relevant; operates G-Cloud and Spark DPS.", "URL": "https://www.crowncommercial.gov.uk/sectors/health", "Feed / API": "No", "Update cadence": "Periodic; pipeline published on site", "Login to view?": "No to browse", "Notes & relevance to digital health": "Health sector landing page lists relevant agreements. Pipeline worth monitoring for upcoming digital frameworks."}, {"Source": "G-Cloud / Digital Marketplace", "Type": "Framework (cloud/digital)", "Owner / operator": "Crown Commercial Service", "Geographic scope": "UK-wide public sector incl. NHS", "What it covers": "Cloud hosting, SaaS software and digital support, the primary procurement route for software-based digital health products.", "URL": "https://www.crowncommercial.gov.uk", "Feed / API": "No", "Update cadence": "Framework refreshes ~annually; buyers search continuously", "Login to view?": "Suppliers register in application windows", "Notes & relevance to digital health": "Most relevant framework for digital health SaaS. Being listed = discoverable to NHS buyers. Track application windows."}, {"Source": "Health Systems Support Framework (HSSF)", "Type": "Framework (digital transformation)", "Owner / operator": "NHS England", "Geographic scope": "England", "What it covers": "Population health management, advanced analytics, digital & service transformation suppliers.", "URL": "https://www.england.nhs.uk/hssf/", "Feed / API": "No", "Update cadence": "Legacy, no new call-offs being initiated", "Login to view?": "No", "Notes & relevance to digital health": "NHS England has stopped initiating new HSSF call-offs; existing ones continue. A refresh/successor has been signalled, watch for it."}, {"Source": "NHS England - Procurement & Commercial", "Type": "Information hub", "Owner / operator": "NHS England", "Geographic scope": "England", "What it covers": "NHS England's own procurement activity, supplier guidance and commercial policy.", "URL": "https://www.england.nhs.uk/nhs-commercial/", "Feed / API": "No", "Update cadence": "As updated", "Login to view?": "No", "Notes & relevance to digital health": "Reference/guidance layer rather than live opportunities, useful for the 'how to contract' editorial content."}, {"Source": "NOE CPC (North of England Commercial Procurement Collaborative)", "Type": "Regional hub", "Owner / operator": "NOE CPC", "Geographic scope": "England (frameworks open to all UK contracting authorities)", "What it covers": "Collaborative frameworks across many categories; Central Commercial Function accredited framework host.", "URL": "https://www.noecpc.nhs.uk", "Feed / API": "Alerts only", "Update cadence": "Periodic", "Login to view?": "Registration for alerts", "Notes & relevance to digital health": "TIER 3. Part of NHS Procurement in Partnership (NHS PiP), members access all four hubs' framework portfolios."}, {"Source": "NHS London Procurement Partnership (LPP)", "Type": "Regional hub", "Owner / operator": "NHS LPP", "Geographic scope": "London + national", "What it covers": "Collaborative NHS frameworks and procurement services.", "URL": "https://www.lpp.nhs.uk", "Feed / API": "Alerts only", "Update cadence": "Periodic", "Login to view?": "Registration for alerts", "Notes & relevance to digital health": "TIER 3. Part of NHS PiP."}, {"Source": "East of England NHS Collaborative Procurement Hub", "Type": "Regional hub", "Owner / operator": "EOECPH", "Geographic scope": "East of England + national", "What it covers": "Collaborative NHS frameworks; runs its own e-tendering portal.", "URL": "https://www.eoecph.nhs.uk", "Feed / API": "Alerts only", "Update cadence": "Periodic", "Login to view?": "Registration for alerts", "Notes & relevance to digital health": "TIER 3. Part of NHS PiP."}, {"Source": "NHS Commercial Solutions", "Type": "Regional hub", "Owner / operator": "NHS Commercial Solutions", "Geographic scope": "South East + national", "What it covers": "Collaborative NHS frameworks and procurement services.", "URL": "Search 'NHS Commercial Solutions', verify current URL", "Feed / API": "Alerts only", "Update cadence": "Periodic", "Login to view?": "Registration for alerts", "Notes & relevance to digital health": "Fourth member of NHS Procurement in Partnership (PiP)."}, {"Source": "HealthTrust Europe", "Type": "Framework operator (private GPO)", "Owner / operator": "HealthTrust Europe", "Geographic scope": "UK", "What it covers": "NHS-accessible framework agreements via an aligned membership / group purchasing model.", "URL": "https://www.healthtrusteurope.com", "Feed / API": "No", "Update cadence": "Periodic", "Login to view?": "No to browse", "Notes & relevance to digital health": "Private group purchasing organisation, an additional framework route alongside the NHS hubs."}, {"Source": "Public Contracts Scotland (PCS)", "Type": "Devolved-nation portal", "Owner / operator": "Scottish Government", "Geographic scope": "Scotland (incl. NHS Scotland boards + National Procurement)", "What it covers": "All Scottish public sector contract opportunities, including NHS National Services Scotland / National Procurement.", "URL": "https://www.publiccontractsscotland.gov.uk", "Feed / API": "Alerts only", "Update cadence": "Continuous", "Login to view?": "Free registration for alerts", "Notes & relevance to digital health": "CPV-code email alerts. PCS-Tender portal for bid submission. Some data feeds available, worth investigating for automation."}, {"Source": "Sell2Wales", "Type": "Devolved-nation portal", "Owner / operator": "Welsh Government", "Geographic scope": "Wales (incl. NHS Wales / NWSSP)", "What it covers": "All Welsh public sector contract opportunities, including NHS Wales Shared Services Partnership.", "URL": "https://www.sell2wales.gov.wales", "Feed / API": "Alerts only", "Update cadence": "Continuous", "Login to view?": "Free registration for alerts", "Notes & relevance to digital health": "CPV-code email alerts."}, {"Source": "eTendersNI", "Type": "Devolved-nation portal", "Owner / operator": "NI Central Procurement Directorate", "Geographic scope": "Northern Ireland (incl. HSC / BSO PaLS)", "What it covers": "Northern Ireland public sector tenders above thresholds, including Health & Social Care via BSO Procurement and Logistics Service.", "URL": "https://etendersni.gov.uk, verify current URL", "Feed / API": "Alerts only", "Update cadence": "Continuous", "Login to view?": "Free registration for alerts", "Notes & relevance to digital health": "CPV-code alerts."}, {"Source": "NHS Innovation Service", "Type": "Innovation front door", "Owner / operator": "NHS England / Health Innovation Network (12 support orgs)", "Geographic scope": "England", "What it covers": "Free centralised 'front door' that matches healthcare innovations to relevant support organisations.", "URL": "https://innovation.nhs.uk", "Feed / API": "No", "Update cadence": "As updated", "Login to view?": "Free account to submit an innovation", "Notes & relevance to digital health": "Not a live-opportunities portal, the navigation/support layer. Useful editorial reference and a signposting partner."}, {"Source": "NICE - National HealthTech Access Programme", "Type": "Evaluation / adoption route", "Owner / operator": "NICE (with DHSC & NHS England)", "Geographic scope": "England", "What it covers": "From April 2026 NICE expands technology appraisals to cover digital health technologies, putting digital tools on a legal par with medicines for reimbursement.", "URL": "https://www.nice.org.uk", "Feed / API": "No", "Update cadence": "Programme-driven", "Login to view?": "No", "Notes & relevance to digital health": "Major NEW route to watch, national reimbursement pathway for digital health. Track evaluation calls and guidance."}, {"Source": "Health Innovation Network (15 regional networks)", "Type": "Innovation support network", "Owner / operator": "Health Innovation Networks (formerly AHSNs)", "Geographic scope": "England (15 regional)", "What it covers": "Regional innovation support, Innovation Exchange calls, and the NHS Innovation Accelerator.", "URL": "https://thehealthinnovationnetwork.co.uk", "Feed / API": "No", "Update cadence": "Rolling calls", "Login to view?": "No", "Notes & relevance to digital health": "Regional adoption support and occasional funded programmes, overlaps with the Grants tab."}, {"Source": "Accelerated Access Collaborative (AAC)", "Type": "Innovation route", "Owner / operator": "NHS England / AAC", "Geographic scope": "England", "What it covers": "Umbrella body coordinating innovation adoption programmes across the NHS.", "URL": "https://www.england.nhs.uk/aac/", "Feed / API": "No", "Update cadence": "Programme-driven", "Login to view?": "No", "Notes & relevance to digital health": "Strategic signposting layer, useful for understanding which innovation programmes are live."}, {"Source": "Tech Innovation Framework / GP IT Futures (Digital Care Services)", "Type": "NHS framework / catalogue", "Owner / operator": "NHS England Digital", "Geographic scope": "England (primary care)", "What it covers": "Assured core GP IT systems and digital products for primary care, bought via the Digital Care Services catalogue. Tech Innovation Framework is the successor to GP IT Futures.", "URL": "https://digital.nhs.uk/services/digital-care-services-catalogue/tech-innovation-framework", "Feed / API": "No", "Update cadence": "Continuous catalogue; suppliers assured periodically", "Login to view?": "No to browse catalogue", "Notes & relevance to digital health": "Essential route for anything touching primary care. GP IT Futures continuity contracts run to June 2026; TIF products (cloud, browser-based, open-API) coming on stream from April 2026."}, {"Source": "MedTech Funding Mandate (MTFM)", "Type": "Adoption / funding route", "Owner / operator": "NHS England / Accelerated Access Collaborative", "Geographic scope": "England", "What it covers": "Mandates NHS commissioners and providers to fund a defined list of NICE-approved cost-saving devices, diagnostics and digital products.", "URL": "https://www.england.nhs.uk/aac/what-we-do/how-can-the-aac-help-me/the-medtech-funding-mandate/", "Feed / API": "No", "Update cadence": "Annual list updates", "Login to view?": "No", "Notes & relevance to digital health": "Not a portal, a route to guaranteed local funding. Eligibility: positive NICE guidance, net saving within 3 years, budget impact under £20m/year. Health Innovation Networks support adoption."}, {"Source": "CCS technology & digital frameworks (beyond G-Cloud)", "Type": "Framework operator", "Owner / operator": "Crown Commercial Service", "Geographic scope": "UK-wide public sector incl. NHS", "What it covers": "Cross-government technology frameworks beyond G-Cloud, e.g. Digital Specialists and Programmes, Vertical Application Solutions, software resale.", "URL": "https://www.crowncommercial.gov.uk", "Feed / API": "No", "Update cadence": "Framework refreshes periodically", "Login to view?": "No to browse", "Notes & relevance to digital health": "Additional CCS routes relevant to digital health builds and the services around them. Track the framework pipeline."}, {"Source": "Trust / ICB e-sourcing platforms (ProContract, In-tend, Delta eSourcing, Jaggaer)", "Type": "E-sourcing platforms", "Owner / operator": "Various (Proactis, In-tend, etc.)", "Geographic scope": "England (individual trusts / ICBs)", "What it covers": "Sub-threshold and local opportunities published by individual trusts and ICBs not fully migrated to Atamis.", "URL": "Platform-specific (per trust)", "Feed / API": "No", "Update cadence": "Continuous", "Login to view?": "Free registration per platform", "Notes & relevance to digital health": "TIER 3. Declining as Atamis consolidates NHS procurement, but still carries local opportunities. Hard to monitor centrally, editorial/assisted tier."}, {"Source": "Devolved NHS national procurement bodies (NSS, NWSSP, BSO PaLS)", "Type": "NHS national buyers", "Owner / operator": "NHS National Services Scotland; NHS Wales Shared Services Partnership; HSC Business Services Organisation", "Geographic scope": "Scotland / Wales / Northern Ireland", "What it covers": "National procurement arms of NHS Scotland, NHS Wales and HSC Northern Ireland, run national contracts and frameworks for their nations.", "URL": "https://www.nss.nhs.scot  ·  https://nwssp.nhs.wales  ·  https://bso.hscni.net", "Feed / API": "No", "Update cadence": "Periodic", "Login to view?": "No to browse", "Notes & relevance to digital health": "Tenders themselves are published on the devolved portals (PCS, Sell2Wales, eTendersNI). Listed here so the buyer side is visible alongside the portals."}], "grants": [{"Source": "SBRI Healthcare", "Type": "Grant programme", "Owner": "NHS England (delivered via Health Innovation Network)", "Geographic scope": "England / UK", "What it funds": "Themed competitions for innovations addressing unmet NHS need, incl. digital health & AI; plus Investment Readiness support.", "Typical award size": "Phase 1 £50k-£150k; Phase 2 up to £1m", "URL": "https://sbrihealthcare.co.uk", "Feed / alerts": "Competition announcements + newsletter", "Cadence": "Themed competitions in waves", "Notes & relevance to digital health": "TIER 2. Flagship NHS-aligned non-dilutive funding. Open to digital, AI, devices, service improvements."}, {"Source": "NIHR Invention for Innovation (i4i)", "Type": "Grant programme", "Owner": "National Institute for Health and Care Research", "Geographic scope": "England / UK", "What it funds": "Translational funding for medical devices, IVDs and digital health technologies, Product Development Awards, i4i Connect, Challenge Awards.", "Typical award size": "Varies by stream; SMEs up to 100% funded", "URL": "https://www.nihr.ac.uk/research-funding/funding-programmes/invention-for-innovation", "Feed / alerts": "Funding calls page", "Cadence": "Periodic calls, two-stage (outline + full)", "Notes & relevance to digital health": "TIER 2. Bridges proof-of-concept to real-world clinical adoption."}, {"Source": "NIHR (wider programmes)", "Type": "Grant funder", "Owner": "NIHR", "Geographic scope": "England / UK", "What it funds": "Multiple routes incl. AI in Health and Care Award, HealthTech Research Centres, EME programme.", "Typical award size": "Varies widely", "URL": "https://www.nihr.ac.uk", "Feed / alerts": "Funding opportunities page", "Cadence": "Programme-specific (some in waves)", "Notes & relevance to digital health": "AI Award rounds run in waves; check current status. HRCs offer co-development/evaluation access."}, {"Source": "Innovate UK", "Type": "Grant funder (national innovation agency)", "Owner": "Innovate UK (part of UKRI)", "Geographic scope": "UK-wide", "What it funds": "Smart Grants, Biomedical Catalyst, sector competitions; plus Innovate UK Business Growth advisory support.", "Typical award size": "Biomedical Catalyst up to ~£2m for large projects", "URL": "https://www.ukri.org/councils/innovate-uk/", "Feed / alerts": "Via Innovation Funding Service", "Cadence": "Rolling competitions", "Notes & relevance to digital health": "TIER 2. Core non-dilutive funder for UK healthtech R&D."}, {"Source": "Innovation Funding Service (IFS)", "Type": "Aggregator / application portal", "Owner": "Innovate UK / UKRI", "Geographic scope": "UK", "What it funds": "The portal where Innovate UK competitions are listed and applications submitted.", "Typical award size": "n/a (portal)", "URL": "https://apply-for-innovation-funding.service.gov.uk/competition/search", "Feed / alerts": "Competition search, monitorable", "Cadence": "Continuous listings", "Notes & relevance to digital health": "TIER 2. Semi-automatable, competition search can be polled for new health/digital calls."}, {"Source": "UKRI / MRC", "Type": "Grant funder", "Owner": "UK Research and Innovation / Medical Research Council", "Geographic scope": "UK", "What it funds": "Translational and developmental pathway schemes; research-oriented funding.", "Typical award size": "Varies widely", "URL": "https://www.ukri.org", "Feed / alerts": "Funding finder", "Cadence": "Periodic calls", "Notes & relevance to digital health": "More research/evidence-generation oriented, relevant for building the clinical evidence base."}, {"Source": "GOV.UK 'Find a grant'", "Type": "Aggregator", "Owner": "UK Government", "Geographic scope": "UK", "What it funds": "Central cross-government grant finder, broad, not health-specific.", "Typical award size": "Varies", "URL": "https://www.find-government-grants.service.gov.uk", "Feed / alerts": "Search + notifications", "Cadence": "Continuous listings", "Notes & relevance to digital health": "TIER 2. Semi-automatable. Filter for health/digital relevance, high noise."}, {"Source": "Health Innovation Networks - regional funds", "Type": "Funding signposting / regional funds", "Owner": "15 Health Innovation Networks", "Geographic scope": "England (regional)", "What it funds": "Regional innovation calls, Innovation Exchange, NHS Innovation Accelerator and signposting to national funding.", "Typical award size": "Varies by network", "URL": "https://thehealthinnovationnetwork.co.uk", "Feed / alerts": "Per-network newsletters", "Cadence": "Rolling regional calls", "Notes & relevance to digital health": "Fragmented across 15 networks, an editorial aggregation opportunity in itself."}, {"Source": "NIHR HealthTech Research Centres (HRCs)", "Type": "Research collaboration / funding access", "Owner": "NIHR", "Geographic scope": "England", "What it funds": "Funding and in-kind support for innovators to co-develop and evaluate health technologies.", "Typical award size": "Varies", "URL": "https://www.nihr.ac.uk", "Feed / alerts": "Per-centre opportunities pages", "Cadence": "Rolling", "Notes & relevance to digital health": "Access route to NHS evaluation partners as much as a cash grant."}, {"Source": "Wellcome Trust", "Type": "Charitable funder", "Owner": "Wellcome Trust", "Geographic scope": "UK / global", "What it funds": "Health research and translational funding, including some digital/data health.", "Typical award size": "Varies widely", "URL": "https://wellcome.org", "Feed / alerts": "Funding schemes page", "Cadence": "Periodic calls", "Notes & relevance to digital health": "Less NHS-procurement-aligned; relevant for early research-stage digital health."}, {"Source": "Scottish Enterprise / Welsh Government / Invest NI", "Type": "Devolved economic development funders", "Owner": "Devolved governments", "Geographic scope": "Scotland / Wales / NI", "What it funds": "R&D grants and SMART-type awards for companies based in the devolved nations.", "Typical award size": "Varies by scheme", "URL": "https://www.scottish-enterprise.com (+ equivalents)", "Feed / alerts": "Per-agency listings", "Cadence": "Rolling", "Notes & relevance to digital health": "Eligibility tied to company location, worth a dedicated 'by nation' filter on the site."}, {"Source": "Condition-specific charity funders (BHF, Cancer Research UK, etc.)", "Type": "Charitable funders", "Owner": "Disease-focused charities", "Geographic scope": "UK", "What it funds": "Innovation and translational awards tied to specific disease areas.", "Typical award size": "Varies widely", "URL": "Multiple (per charity)", "Feed / alerts": "Per-charity funding pages", "Cadence": "Periodic calls", "Notes & relevance to digital health": "Relevant only where the product has a disease focus, a 'by condition' tag would surface these well."}, {"Source": "Digital Catapult & other Catapults", "Type": "Innovation support / occasional funded programmes", "Owner": "Catapult Network", "Geographic scope": "UK", "What it funds": "Challenge-led programmes, accelerator places and occasional funded cohorts.", "Typical award size": "Varies (often in-kind + cash)", "URL": "https://www.digicatapult.org.uk", "Feed / alerts": "Programme announcements", "Cadence": "Programme-driven", "Notes & relevance to digital health": "More support-in-kind than grant cash, but worth monitoring for funded calls."}, {"Source": "NHS England transformation / innovation funding pots", "Type": "NHS programme funding", "Owner": "NHS England (policy-driven)", "Geographic scope": "England", "What it funds": "Episodic funding pots tied to policy, e.g. AI/diagnostic funds, 10 Year Health Plan-linked allocations.", "Typical award size": "Varies, often large, time-limited", "URL": "https://www.england.nhs.uk", "Feed / alerts": "No central feed", "Cadence": "Episodic / policy-driven", "Notes & relevance to digital health": "Hardest to track and highest editorial value, exactly the 'stealth' problem from the procurement side."}, {"Source": "Horizon Europe - Health Cluster (Cluster 1) & EIC Accelerator", "Type": "International grant programme", "Owner": "European Commission (UK associated)", "Geographic scope": "UK (associated) + EU", "What it funds": "Collaborative health research & innovation (Cluster 1) and deep-tech SME/startup funding (EIC Accelerator). UK orgs are eligible; Cluster 1 needs a consortium of 3+ countries.", "Typical award size": "Cluster 1 up to ~EUR 90m per call; EIC Accelerator up to ~EUR 2.5m grant + equity", "URL": "https://research-and-innovation.ec.europa.eu/funding/funding-opportunities/funding-programmes-and-open-calls/horizon-europe/cluster-1-health_en", "Feed / alerts": "Work programme + fixed cut-off dates", "Cadence": "Annual work programmes; EIC has ~6 cut-offs/year", "Notes & relevance to digital health": "Major route since UK association. EIC Accelerator cut-offs are predictable and monitorable. Innovate UK Business Connect signposts UK applicants."}, {"Source": "The Health Foundation", "Type": "Charitable funder", "Owner": "The Health Foundation", "Geographic scope": "UK", "What it funds": "Innovation and improvement programmes, e.g. Tech for Better Care (technology-enabled care at home), plus research and improvement grants.", "Typical award size": "Programme-dependent (e.g. Tech for Better Care ~£2m programme)", "URL": "https://www.health.org.uk/funding-and-partnerships", "Feed / alerts": "Programme calls page", "Cadence": "Periodic programme calls", "Notes & relevance to digital health": "Increasingly focused on technology and AI in care, good fit for digital health with a service-improvement angle."}, {"Source": "LifeArc", "Type": "Medical research charity", "Owner": "LifeArc", "Geographic scope": "UK / global", "What it funds": "Translational funding and partnerships for therapeutics, diagnostics and medtech; LifeArc Ventures provides (dilutive) seed-Series B investment.", "Typical award size": "Varies by call / partnership", "URL": "https://www.lifearc.org/work-with-us/funding-and-partnerships/", "Feed / alerts": "Funding & partnerships page", "Cadence": "Periodic calls", "Notes & relevance to digital health": "Strongest for diagnostics / medtech translation. Note: LifeArc Ventures is equity, not non-dilutive."}, {"Source": "Office for Life Sciences (OLS)", "Type": "Government funder", "Owner": "DHSC / DSIT (Office for Life Sciences)", "Geographic scope": "UK", "What it funds": "Life sciences sector funds and programmes, e.g. innovative manufacturing funds and sector growth programmes.", "Typical award size": "Programme-dependent, often large, time-limited", "URL": "https://www.gov.uk/government/organisations/office-for-life-sciences", "Feed / alerts": "GOV.UK announcements", "Cadence": "Episodic / policy-driven", "Notes & relevance to digital health": "Policy-driven pots, high editorial value, hard to track via a feed."}, {"Source": "Regional & Combined Authority innovation funds + UK Shared Prosperity Fund", "Type": "Regional economic development funding", "Owner": "Combined Authorities / local government", "Geographic scope": "UK (regional)", "What it funds": "Regional health innovation funds and economic development grants run by Combined Authorities (e.g. Greater Manchester, West Midlands) and the UK Shared Prosperity Fund.", "Typical award size": "Varies widely by region", "URL": "Multiple (per authority)", "Feed / alerts": "Per-authority listings", "Cadence": "Rolling / episodic", "Notes & relevance to digital health": "Eligibility tied to company location / region. Fragmented, a 'by region' filter on the site would surface these."}]}, "portalGuides": {"updated": "2026-05-27T00:00:00Z", "note": "Per-portal how-to-apply guides. Keyed by slug. `aliases` lets the opportunity source string match back to the right portal even when wording differs slightly. Author/edit freely, this file is loaded by bundle.py into data.js and rendered on directory.html and opportunity.html. Reviewed and revised 27 May 2026 against current public sources (Procurement Act 2023 / Central Digital Platform, recent SBS framework, NOE CPC Atamis migration, etc).", "portals": {"fts": {"name": "Find a Tender Service (FTS)", "aliases": ["Find a Tender Service", "Find a Tender", "FTS"], "intro": "Find a Tender is the UK's central public procurement notice platform for above-threshold opportunities and Procurement Act 2023 notices. Under the Act it has become part of the Central Digital Platform, where suppliers can store commonly-used information once and reuse it across procurements. The tender response itself usually still happens on the buyer's named e-sourcing system (Atamis, Jaggaer, SAP Ariba, ProContract, In-tend, Delta, PCS-Tender, etc).", "hoops": ["No registration needed to browse or set up keyword alerts.", "When a notice catches your eye, follow it through to the buyer's named e-sourcing system. That is where you actually register and submit.", "Have a basic supplier pack ready before you start: company info, two or three reference clients, insurance certificates. For clinical or data products, expect to need security/clinical assurance evidence (ISO 27001 or a roadmap, Cyber Essentials, DCB0129 where the product affects clinical decisions, DPIA/DTAC or equivalent). Exact requirements vary by framework and lot."], "steps": ["Create a saved search with CPV codes for digital health (72000000 IT services, 85100000 health services, 33000000 medical devices) and the keywords you care about.", "Read the notice in full: contract value, lot structure, evaluation criteria, deadlines, and any pre-qualification requirements.", "Follow the 'How to access this opportunity' link to register on the buyer's e-sourcing portal.", "Download the SQ and ITT documents as soon as they are available. Windows are tight."], "gotchas": "FTS only carries notices above the relevant public procurement threshold. Lower-value opportunities go to Contracts Finder. Older legacy notices may still appear in OJEU/Find-a-Tender style; current procurements use Procurement Act notices."}, "contracts-finder": {"name": "Contracts Finder", "aliases": ["Contracts Finder"], "intro": "Contracts Finder lists lower-value central government and NHS opportunities, plus pipelines and award notices. Same model as FTS: a notice service that points you at the buyer's actual e-sourcing platform. Threshold is generally over £12,000 including VAT for central government and over £30,000 including VAT for sub-central bodies including NHS trusts.", "hoops": ["A free account lets you save searches and get email alerts. You do not need one to browse.", "You will still need to register on whatever portal the notice links to (Atamis, ProContract, Jaggaer, In-tend, etc) to actually bid."], "steps": ["Set up a Contracts Finder account and save searches on CPV codes plus 'NHS', 'digital', 'AI', 'analytics', 'patient record'.", "When a relevant notice lands, read the contract value and notice type carefully. A 'Pipeline' notice is early warning, not a live tender.", "Click the buyer's link, register on their portal, download the documents.", "Mark the deadline in your calendar and work back: SQ first, then ITT, then clarifications window."], "gotchas": "Some NHS trusts under-publish to Contracts Finder and only post on their own e-sourcing system. The MyClinical Growth daily brief picks up both."}, "atamis": {"name": "Atamis (Health Family eCommercial System)", "aliases": ["Atamis", "Atamis - Health Family eCommercial System", "Atamis Health Family"], "intro": "Atamis is the NHS Health Family eCommercial system used by many NHS organisations and NHS England for procurement activity, tenders, contracts, supplier management and related commercial workflows. NHS England has previously reported tens of thousands of registered suppliers. NOE CPC has also adopted Atamis, so its coverage is expanding beyond the original Health Family.", "hoops": ["Free supplier registration is required to see most opportunity detail and to bid.", "Registration asks for company information, financial details, certifications, and a self-assessment of categories you supply.", "Pick category codes carefully. Alerts run off them. Tick too few and you miss opportunities; tick everything and the inbox is unreadable."], "steps": ["Register a supplier account at the Atamis Health Family supplier portal.", "Complete your supplier profile fully. Buyers see this when shortlisting.", "Set category alerts. For digital health these usually sit under IT services, clinical software, medical devices and consultancy.", "When a notice lands, express interest in the system to receive the SQ/ITT documents.", "Use the in-portal clarifications tab. Questions asked there are answered to all bidders, which can shape your response."], "gotchas": "Atamis category coverage is uneven across organisations. A digital health tender at one trust may sit under 'IT consultancy', at another under 'Clinical systems'. Set multiple alerts."}, "sbs": {"name": "NHS Shared Business Services (SBS)", "aliases": ["NHS Shared Business Services", "NHS SBS", "SBS", "Shared Business Services"], "intro": "NHS SBS is a DHSC / Sopra Steria joint venture that runs national framework agreements for NHS and public sector organisations. They are the operator of the £900m (including VAT) Healthcare AI Solutions framework. SBS is the source most likely to release a major framework with almost no public noise. The 'stealth release' problem.", "hoops": ["Submissions for SBS frameworks go through the e-sourcing platform named in each notice. The Healthcare AI Solutions framework, for example, uses SAP Ariba.", "Register on the relevant platform with company details, references and category interests.", "For most clinical or data frameworks expect to need: ISO 27001 (or a credible roadmap), Cyber Essentials or Cyber Essentials Plus, DCB0129 clinical safety case where the product affects clinical decisions, DTAC self-assessment, GDPR/DPIA documentation. Exact requirements depend on the framework and lot.", "Framework competitions usually have a formal Selection Questionnaire (SQ) gate before you reach the technical response. Fail the SQ and you do not see the ITT."], "steps": ["Subscribe to the SBS framework news feed and the MyClinical Growth daily brief so you do not miss a launch.", "When a framework opens, identify the named e-sourcing platform from the FTS notice and register there.", "Download the FTS notice plus the SBS-specific framework documents. The lot structure is often the most important thing to read first.", "Decide which lots you are realistically credible in. Bidding for too many dilutes the response and looks unfocused.", "Build the SQ response against the actual scoring criteria, not against what you wish was being asked. Then write the ITT.", "Submit at least 24 hours before the deadline. Portal upload failures in the final hour are common."], "gotchas": "SBS frameworks often run for four years. Missing one means a four-year wait. Clinical safety and DTAC paperwork takes weeks, not days, so start it the moment you see a planned procurement notice (not the day the ITT drops)."}, "nhs-supply-chain": {"name": "NHS Supply Chain (Medical Technology Innovation DPS)", "aliases": ["NHS Supply Chain", "NHS Supply Chain / Spark DPS", "Supply Chain Coordination Ltd", "Spark DPS", "Medical Technology Innovation DPS", "Innovation DPS"], "intro": "NHS Supply Chain (Supply Chain Coordination Ltd) is the main route for products and consumables into the NHS. For innovation, the relevant route is the Medical Technology Innovation DPS (a seven-year dynamic purchasing system, often referred to in market shorthand as 'Spark' or 'Innovation DPS'). Unlike a framework, the DPS is open to new suppliers continuously, not just at refresh windows.", "hoops": ["Free registration on the Supply Chain supplier portal.", "Innovation DPS application asks for product description, evidence (clinical, regulatory, real-world), and a structured questionnaire response.", "Where the product is a regulated medical device, CE/UKCA marking is required, and for software-as-medical-device that includes a current technical file."], "steps": ["Identify which Innovation DPS category your product fits. Categories are narrow on purpose. The wrong category will get you rejected on a technicality.", "Apply via the Innovation DPS portal. Turnaround is usually weeks rather than months.", "Once accepted, you sit on the DPS and respond to mini-competitions when NHS organisations call off.", "Keep your DPS profile up to date. Buyers filter on it."], "gotchas": "Strongest for medtech, devices, diagnostics and connected hardware. Pure software (e.g. SaaS clinical decision support) is a weaker fit and is better served by G-Cloud or the NHS Innovation Service."}, "ccs-health": {"name": "Crown Commercial Service (CCS), Health", "aliases": ["Crown Commercial Service", "Crown Commercial Service (CCS) - Health", "CCS", "CCS Health"], "intro": "CCS runs cross-government commercial agreements used by NHS organisations, including G-Cloud and several technology, digital, cyber and consultancy frameworks. To bid you go via the framework you care about, not via CCS as a single portal. CCS does not run Spark / Innovation DPS, which sits with NHS Supply Chain.", "hoops": ["Each CCS framework has its own qualification rules and its own bid window. Frameworks refresh on different cycles.", "Expect Cyber Essentials as a baseline. Cyber Essentials Plus or ISO 27001 where risk, data sensitivity or framework rules require it.", "Financial standing tests are typical. Two years of audited accounts and a turnover threshold relative to the contract value."], "steps": ["Use the CCS pipeline page to see which frameworks are open, in market, or coming.", "Pick the one or two you are realistic for. Resist the urge to apply to everything.", "Watch the planned-procurement notice on FTS for the precise SQ/ITT release date.", "Apply within the window. Out-of-window applications cannot be considered (not negotiable)."], "gotchas": "Frameworks have hard application windows. Miss them and you wait until the next refresh, which can be two to four years away."}, "g-cloud": {"name": "G-Cloud / Digital Marketplace", "aliases": ["G-Cloud", "G-Cloud / Digital Marketplace", "Digital Marketplace", "GCloud"], "intro": "G-Cloud is the main route for cloud hosting, SaaS and cloud support into the public sector, including the NHS. If you sell software-as-a-service to clinicians or administrators, being on G-Cloud is the difference between being findable and not.", "hoops": ["Application windows open roughly annually. You can only apply when CCS opens a new iteration (G-Cloud 14, 15, etc).", "Cyber Essentials is the baseline and Cyber Essentials Plus is commonly required, depending on the iteration and service type.", "You publish a service description, pricing card and terms. These are public and searchable. Buyers compare on them.", "Where consultancy or implementation services are included, buyers often expect clear role-based day rates, commonly mapped to SFIA-style levels."], "steps": ["Watch for the next G-Cloud application window opening on the Digital Marketplace site or in the daily brief.", "Prepare your service descriptions in advance. Each service is a separate listing and needs its own description and pricing.", "Submit during the window. Late submissions are not accepted.", "Once listed, NHS buyers find you via search. The way you write your service title and description determines whether you appear."], "gotchas": "Being on G-Cloud does not generate sales by itself. NHS buyers still need to find you and run a call-off mini-competition. Treat your G-Cloud listing as SEO: keywords matter."}, "hssf": {"name": "Health Systems Support Framework (HSSF)", "aliases": ["Health Systems Support Framework", "HSSF"], "intro": "HSSF is NHS England's framework for population health management, advanced analytics and digital and service transformation suppliers. NHS England has stopped initiating new call-offs and existing ones continue. Do not treat HSSF as an active route for new suppliers.", "hoops": ["If you are already on it, existing call-offs continue.", "New suppliers cannot currently get on. Watch for successor or replacement routes."], "steps": ["Track NHS England digital transformation pipeline announcements.", "Subscribe to the daily brief so you see any successor framework launch the day it goes live."], "gotchas": "Energy is better spent on G-Cloud, SBS frameworks, or NHS Innovation Service rather than chasing HSSF."}, "nhs-england-procurement": {"name": "NHS England Procurement & Commercial", "aliases": ["NHS England", "NHS England - Procurement & Commercial", "NHS England Procurement", "NHS England Digital", "NHS Digital", "NHS Digital (legacy)", "NHSX"], "intro": "NHS England's procurement team covers the full lifecycle: market engagement, supplier selection, contract management and expiry planning. Central programmes (e.g. the Federated Data Platform, national digital programmes) tend to be very large, very visible, and go via Atamis or directly via Find a Tender.", "hoops": ["For digital, data or clinical programmes, expect requirements around ISO 27001, Cyber Essentials (often Plus), clinical safety (DCB0129/0160), data protection, DTAC or equivalent assurance, NHS Data Security and Protection Toolkit submission and DPIA materials. Exact mix depends on the programme.", "Past performance with the NHS is heavily weighted. First-time NHS suppliers should expect to partner with an established prime."], "steps": ["Track the NHS England procurement pipeline page and FTS notices labelled 'NHS England'.", "For large programmes, decide early whether you are bidding as prime or sub. Then build the consortium accordingly.", "Engage in the pre-market engagement events. They are not just for show. The questions you ask shape the final specification."], "gotchas": "Not SME-friendly procurements. If you are pre-revenue, the realistic route is to partner with a prime rather than bid as lead."}, "noe-cpc": {"name": "NOE CPC (North of England Commercial Procurement Collaborative)", "aliases": ["NOE CPC", "NOE CPC (NHS North of England Commercial Procurement Collaborative)", "NHS North of England Commercial Procurement Collaborative"], "intro": "NOE CPC is an NHS England Central Commercial Function accredited framework host that runs frameworks for trusts in the North of England (and beyond). They run several digital and clinical frameworks each year.", "hoops": ["NOE CPC has moved into the Atamis Health Family environment, so do not assume In-tend or any other platform unless the live notice says so.", "Free supplier registration.", "Standard NHS supplier requirements apply: insurance, financial standing, relevant certifications for the category."], "steps": ["Register on Atamis if you have not already.", "Set category alerts for NOE CPC's framework families.", "When a notice lands, follow the named platform in the notice. Express interest there to receive documents.", "Submit within deadline. Portal-only submission rules are strict."], "gotchas": "NOE CPC publishes a yearly pipeline. Read it in January. Many launches happen Q2 and Q3."}, "lpp": {"name": "NHS London Procurement Partnership (LPP)", "aliases": ["NHS LPP", "London Procurement Partnership", "NHS London Procurement Partnership (LPP)", "London Procurement Partnership (NHS LPP)"], "intro": "LPP is one of the NHS procurement hubs, serving London and beyond. Digital and clinical frameworks come up regularly. Bidding goes via the e-sourcing platform LPP names in each notice.", "hoops": ["Free supplier registration on the relevant LPP portal.", "Standard SQ process."], "steps": ["Register on the named LPP portal.", "Set alerts on the categories that match.", "Express interest in tenders you want to receive."], "gotchas": "London reference sites and mature clinical safety documentation are commercially helpful, especially for digital health suppliers. Have your DCB0129 evidence ready to cite, not assemble."}, "ee-collab": {"name": "East of England NHS Collaborative Procurement Hub", "aliases": ["East of England NHS Collaborative", "East of England NHS Collaborative Procurement Hub", "EE Collab"], "intro": "Regional collaborative procurement hub. Runs frameworks and call-offs for East of England trusts. The hub now links suppliers to Atamis as the single eCommercial system used across the NHS, alongside its own e-tendering portal.", "hoops": ["Always follow the portal named in the live notice."], "steps": ["Monitor the hub's tender pipeline and Atamis-linked opportunities.", "Register on whichever portal the live notice points to."], "gotchas": "Smaller hub, less predictable cadence. Worth setting an alert on Atamis under 'East of England' rather than checking the hub site directly."}, "nhs-commercial-solutions": {"name": "NHS Commercial Solutions", "aliases": ["NHS Commercial Solutions"], "intro": "NHS Commercial Solutions is the South East NHS procurement hub and one of the four NHS Procurement in Partnership hubs alongside NOE CPC, LPP and East of England. It runs collaborative frameworks across clinical and corporate categories.", "hoops": ["Bid via the e-sourcing portal the notice points to.", "Standard NHS supplier requirements apply."], "steps": ["Register on the relevant portal.", "Express interest in tenders that match."], "gotchas": "Coverage overlaps with LPP for some London-fringe trusts. The notice itself will tell you which hub is running it."}, "healthtrust-europe": {"name": "HealthTrust Europe", "aliases": ["HealthTrust Europe", "HTE"], "intro": "HealthTrust Europe is a procurement partner to over a thousand organisations across public and private sectors. Its public sector frameworks are designed for contracting authorities, particularly those delivering health and social care. Less common for pure digital health, more common for medtech, devices and outsourced clinical services. Worth knowing about if your product crosses into medtech.", "hoops": ["Supplier registration on the HTE supplier portal.", "Strong commercial terms expected. HTE is a buying group, not a charity."], "steps": ["Register if your product fits one of the HTE categories.", "Engage early with the commercial team where appropriate. The commercial model and framework access route can differ from NHS-owned procurement hubs, and the unwritten rules are real."], "gotchas": "Some trusts use HTE in parallel with NHS Supply Chain. Check whether the buyer is HTE-affiliated before pitching commercials."}, "pcs": {"name": "Public Contracts Scotland (PCS)", "aliases": ["Public Contracts Scotland", "PCS"], "intro": "PCS is Scotland's official public sector opportunity portal, used for Scottish public sector notices including NHS Scotland. PCS-Tender is the linked national e-tendering system.", "hoops": ["Free registration on PCS gives you alerts.", "PCS-Tender (separate) is where you actually submit bids."], "steps": ["Register on PCS, set CPV and keyword alerts.", "When a notice lands, follow through to PCS-Tender and register a bid account.", "Submit before deadline. Late submissions are rejected automatically by the system."], "gotchas": "Do not assume English DTAC alone satisfies Scottish requirements. Check NHS Scotland information governance, cyber, clinical safety and technical assurance requirements for the specific procurement."}, "sell2wales": {"name": "Sell2Wales", "aliases": ["Sell2Wales"], "intro": "Welsh Government-backed public procurement portal. NHS Wales (via NHS Wales Shared Services Partnership, NWSSP) advertises tender opportunities here.", "hoops": ["Free registration for alerts.", "Bids go via eTenderWales or the platform the notice specifies."], "steps": ["Register on Sell2Wales.", "Set alerts on NHS Wales and health-related CPV codes.", "Follow through to the named platform to bid."], "gotchas": "Welsh-language considerations apply for patient-facing services. Check the specification."}, "etendersni": {"name": "eTendersNI", "aliases": ["eTendersNI", "eSourcingNI"], "intro": "eTendersNI is the e-tendering platform for Northern Ireland public sector opportunities, including HSC procurements advertised by BSO PaLS.", "hoops": ["Free registration.", "NI HSC has a distinct procurement architecture. Trusts buy via BSO PaLS for most goods and services."], "steps": ["Register on eTendersNI.", "Set alerts for HSC NI categories."], "gotchas": "Lower volume than England, Scotland or Wales. Worth tracking if you want UK-wide coverage."}, "nhs-innovation-service": {"name": "NHS Innovation Service", "aliases": ["NHS Innovation Service"], "intro": "Not a tender portal. A national front door for innovators to get free, structured support from NHS England, the Health Innovation Networks, NICE and others. The right starting point if you are pre-procurement and want the NHS to take you seriously.", "hoops": ["Free to join.", "You submit your innovation through a structured form. NHS Innovation Service assigns you support based on your maturity (idea, evidence-gathering, scaling).", "Treat it as a readiness and navigation route, not a direct sales channel. Editorially, expect a 6 to 12 month engagement before it pays off."], "steps": ["Register and submit your innovation at the NHS Innovation Service site.", "Be honest about your evidence base. Overclaiming gets you assigned to the wrong support tier.", "Engage with the assigned advisors. The introductions they make are the actual value."], "gotchas": "Do not expect contracts to drop out of this. Expect a clearer evidence pathway, the right people in your network, and a stronger story by the time you go to procurement."}, "nice-htap": {"name": "NICE digital health technology pathways", "aliases": ["NICE", "NICE - National HealthTech Access Programme", "NICE HealthTech"], "intro": "From April 2026 NICE expanded its technology appraisal routes to cover selected digital health technologies, creating a national reimbursement pathway where positive guidance applies. This puts high-impact healthtech that meets critical NHS needs on a footing closer to medicines for reimbursement, but only for selected, high-impact tools, not every digital product.", "hoops": ["Eligible products are typically digital health technologies and medtech with a credible cost-saving or outcomes case.", "You submit an evidence package against the NICE Evidence Standards Framework (ESF). Use the ESF to understand evidence expectations rather than treating it as a tick-box.", "Expect months, not weeks. This is the real route to system-wide adoption."], "steps": ["Read the NICE ESF carefully and self-assess your evidence tier honestly.", "If your evidence justifies it, apply via the NICE digital health team.", "Build the evidence dossier they ask for. Independent evaluation is heavily weighted."], "gotchas": "If your evidence is mostly developer claims with no comparative data, invest in a real-world evaluation before applying. The committee will not approve on assertions."}, "hin": {"name": "Health Innovation Networks (15 regional)", "aliases": ["Health Innovation Network", "Health Innovation Network (15 regional networks)", "HIN", "AHSN"], "intro": "15 regional Health Innovation Networks (formerly Academic Health Science Networks), established by NHS England to spread innovation at pace and scale. Free support, real networks, occasional small contracts. HINs open doors, support evidence generation and help adoption. They do not replace procurement.", "hoops": ["Free to engage. You pitch your innovation to the regional HIN.", "Each HIN has its own focus areas. Check before you approach."], "steps": ["Identify the HIN(s) whose region and priorities match your product.", "Use their innovator support form to introduce yourself.", "Ask for introductions to specific trusts, ICBs or clinical leads. That is the real value."], "gotchas": "HINs are not procurement bodies. They open doors. The actual contract still goes through a normal NHS procurement route."}, "aac": {"name": "Accelerated Access Collaborative (AAC)", "aliases": ["Accelerated Access Collaborative", "AAC", "NHS England / Accelerated Access Collaborative", "NHSX / NIHR / Accelerated Access Collaborative"], "intro": "AAC sits inside NHS England as a national innovation adoption layer, not a procurement portal. Relevant levers include the NHS Innovation Accelerator (delivered with the 15 Health Innovation Networks), Rapid Uptake Products, the MedTech Funding Mandate, and the Innovation for Healthcare Inequalities Programme (InHIP).", "hoops": ["AAC programmes are application-based and competitive. They want evidence, not pitches.", "Most AAC routes expect NICE guidance or equivalent independent endorsement of cost-effectiveness."], "steps": ["Identify the right AAC programme for your product (Innovation Accelerator if you are scaling, InHIP if your product addresses health inequalities, MTFM if NICE has approved you).", "Apply during the open window. Windows are usually annual.", "Lean on your HIN to support the application."], "gotchas": "AAC programmes are signalling, not direct procurement. Selection means NHS England visibly endorses you, which makes ICB conversations easier."}, "gp-it-futures": {"name": "Digital Care Services / Digital Services for Integrated Care", "aliases": ["GP IT Futures", "Tech Innovation Framework", "Tech Innovation Framework / GP IT Futures (Digital Care Services)", "TIF", "Digital Care Services", "Digital Services for Integrated Care"], "intro": "Digital Care Services and Digital Services for Integrated Care are the current catalogue and assurance route for GP and primary-care digital services. GP IT Futures and the Tech Innovation Framework sit within that broader evolution. If you sell anything that touches primary care, this is the gating step.", "hoops": ["Assurance against the NHS England Digital Care Services Capabilities and Standards. Detailed and prescriptive.", "Expect DTAC, DCB0129, GDPR/DPIA, and NHS Data Security and Protection Toolkit submission.", "Catalogue approval is staged. Expect months."], "steps": ["Read the relevant catalogue capability specification.", "Self-assess against it honestly. Gaps mean rejection.", "Apply via the Digital Care Services route. Buyer mini-competitions follow.", "Once on, GP practices and PCNs can call you off the catalogue."], "gotchas": "The platform has been evolving from GP IT Futures into a broader integrated care model. If primary care is a target market, treat catalogue presence as table-stakes."}, "mtfm": {"name": "MedTech Funding Mandate (MTFM)", "aliases": ["MedTech Funding Mandate", "MTFM"], "intro": "MTFM creates a national policy expectation and funding support for selected NICE-recommended cost-saving technologies, making local adoption much easier than normal procurement routes. The strongest commercial signal in the system for the products it covers.", "hoops": ["You need positive NICE guidance (Medical Technologies, Diagnostics, or relevant HealthTech route) with a cost-saving conclusion.", "The product must be ready to scale, not a pilot."], "steps": ["Get NICE evaluation first. Without it, MTFM is not available to you.", "Once approved by NICE on cost-saving terms, AAC notifies you of eligibility for MTFM listing.", "Listing brings active commissioner engagement and ICB rollout support."], "gotchas": "Only a small number of products carry MTFM at any time. Getting on is a multi-year journey. Plan investment accordingly."}, "ccs-tech": {"name": "CCS technology & digital frameworks (beyond G-Cloud)", "aliases": ["CCS technology", "CCS technology & digital frameworks (beyond G-Cloud)", "CCS digital"], "intro": "CCS runs wider technology, cyber, software, data and digital services frameworks beyond G-Cloud. These can be relevant for healthtech suppliers providing implementation, analytics, cyber, integration or specialist delivery services around the core product. Specific framework names change, expire and refresh, so check the CCS pipeline for the current set.", "hoops": ["Each framework has its own application window and SQ rules.", "Expect Cyber Essentials as a baseline, and Cyber Essentials Plus or ISO 27001 where risk, data sensitivity or framework rules require it.", "Sub-contractor disclosure is required. Plan your supply chain early."], "steps": ["Use the CCS pipeline page to plan your applications 6-12 months ahead.", "Apply within the window for each framework that matches.", "Once on, monitor the framework's call-off competitions for NHS buyers."], "gotchas": "Application windows close. Set calendar reminders before each framework's expected refresh date. The cost of missing one is 2-4 years of exclusion."}, "trust-esourcing": {"name": "Trust / ICB e-sourcing platforms", "aliases": ["Trust e-sourcing", "Trust / ICB e-sourcing platforms (ProContract, In-tend, Delta eSourcing, Jaggaer)", "ProContract", "In-tend", "Delta eSourcing", "Jaggaer"], "intro": "Individual trusts, ICBs and CSUs may still use local e-sourcing platforms such as ProContract, In-tend, Delta eSourcing, Jaggaer or Atamis. When you click through from a Contracts Finder or FTS notice, the public notice should tell you which platform to express interest and submit on.", "hoops": ["Each platform needs its own free supplier account.", "Platforms are buyer-agnostic. The same login lets you bid on every organisation that uses that platform."], "steps": ["Create accounts on at least: Atamis, ProContract, In-tend, Delta eSourcing and Jaggaer. Free, takes 10 minutes each.", "Set alerts where the platform allows it.", "Always express interest in a notice via the buyer's chosen platform. That is the only way to receive the documents."], "gotchas": "Some trusts run procurements only via their local platform, never via Atamis or Find a Tender. The MyClinical Growth daily brief catches what it can, but trust portals are the long tail of NHS procurement."}, "devolved": {"name": "Devolved NHS national procurement bodies (NSS, NWSSP, BSO PaLS)", "aliases": ["NSS", "NWSSP", "BSO PaLS", "Devolved NHS national procurement bodies (NSS, NWSSP, BSO PaLS)"], "intro": "NHS Scotland (NSS National Procurement), NHS Wales (NWSSP) and Health and Social Care NI (BSO PaLS) each run their own national procurement bodies. Same idea as NHS Supply Chain in England but with different rules, portals and assurance regimes.", "hoops": ["Each devolved nation has its own supplier registration.", "Scotland: NSS uses PCS for tender notices and has its own information governance and cyber requirements.", "Wales: NWSSP uses Sell2Wales and its e-tendering portal.", "NI: BSO PaLS uses eTendersNI."], "steps": ["Register on each devolved body's supplier portal if you intend to sell into that nation.", "Map your English certifications to their equivalents. Some translate, some do not.", "Plan for separate procurement cycles. The devolved nations do not follow NHS England's calendar."], "gotchas": "DTAC is England-specific. Scotland, Wales and Northern Ireland may recognise some of the same underlying evidence, but suppliers should check local IG, cyber, clinical safety and technical assurance requirements before claiming compliance."}}}};
